			$sql = 'SELECT COUNT(rule_id) AS num_rules
				FROM ' . PRIVMSGS_RULES_TABLE . '
				WHERE user_id = ' . (int) $user->data['user_id'];
			$result = $db->sql_query($sql);
			$num_rules = (int) $db->sql_fetchfield('num_rules');
