			if ($num_rules >= 5000)
			{
				trigger_error('RULE_LIMIT_REACHED');
			}

			$sql = 'INSERT INTO ' . PRIVMSGS_RULES_TABLE . ' ' . $db->sql_build_array('INSERT', $rule_ary);
			$db->sql_query($sql);

