		}
		else
		{
			for($i = 0; $i < count($test_options); $i++)
			{
				$o = $test_options[$i];
				$option_count = $o->option_count();

				echo '<input type="hidden" name="test_add[]" value="' . $test_profile->get_identifier() . '" />';

				if(isset($_GET['build_suite']))
